<?php
if (!defined('ABSPATH')) exit;
use Elementor\Widget_Base; use Elementor\Controls_Manager; use Elementor\Icons_Manager;
class bina_Contact_Info_CTA_Widget extends Widget_Base {
    public function get_name(){return 'bina_contact_info_cta';}
    public function get_title(){return __('Contact Info + CTA (Static)','bina');}
    public function get_icon(){return 'eicon-info-circle';}
    public function get_categories(){return ['general'];}
    protected function _register_controls(){
        $this->start_controls_section('s',['label'=>__('Content','bina')]);
        $this->add_control('work_icon_upload',['label'=>__('Work Time Main Icon Upload','bina'),'type'=>Controls_Manager::MEDIA]);
        $this->add_control('work_icon',['type'=>Controls_Manager::ICONS,'default'=>['value'=>'fas fa-clock','library'=>'fa-solid']]);
        $this->add_control('work_title',['type'=>Controls_Manager::TEXT,'default'=>'ساعات العمل']);
        $this->add_control('work_row1_icon_upload',['type'=>Controls_Manager::MEDIA]); $this->add_control('work_row1_icon',['type'=>Controls_Manager::ICONS,'default'=>['value'=>'fas fa-circle-check','library'=>'fa-solid']]); $this->add_control('work_row1_text',['type'=>Controls_Manager::TEXT,'default'=>'الأحد - الخميس: 9 ص - 6 م']);
        $this->add_control('work_row2_icon_upload',['type'=>Controls_Manager::MEDIA]); $this->add_control('work_row2_icon',['type'=>Controls_Manager::ICONS,'default'=>['value'=>'fas fa-circle-check','library'=>'fa-solid']]); $this->add_control('work_row2_text',['type'=>Controls_Manager::TEXT,'default'=>'الجمعة - السبت: مغلق']);
        $this->add_control('loc_icon_upload',['label'=>__('Location Main Icon Upload','bina'),'type'=>Controls_Manager::MEDIA]); $this->add_control('loc_icon',['type'=>Controls_Manager::ICONS,'default'=>['value'=>'fas fa-map-marker-alt','library'=>'fa-solid']]);
        $this->add_control('loc_title',['type'=>Controls_Manager::TEXT,'default'=>'الموقع']); $this->add_control('loc_line1',['type'=>Controls_Manager::TEXT,'default'=>'المملكة العربية السعودية']); $this->add_control('loc_line2',['type'=>Controls_Manager::TEXT,'default'=>'الرياض - جدة - الدمام']);
        $this->add_control('cta_url',['type'=>Controls_Manager::URL,'default'=>['url'=>'https://api.whatsapp.com/send?phone=966573572442']]); $this->add_control('cta_icon_upload',['type'=>Controls_Manager::MEDIA]); $this->add_control('cta_icon',['type'=>Controls_Manager::ICONS,'default'=>['value'=>'fas fa-message','library'=>'fa-solid']]); $this->add_control('cta_text',['type'=>Controls_Manager::TEXT,'default'=>'تواصل عبر واتساب']);
        $this->end_controls_section();
    }
    protected function render(){ $s=$this->get_settings_for_display();
        $w1=$s['work_icon_upload']['url']??''; $wr1=$s['work_row1_icon_upload']['url']??''; $wr2=$s['work_row2_icon_upload']['url']??''; $li=$s['loc_icon_upload']['url']??''; $ci=$s['cta_icon_upload']['url']??''; ?>
    <section class="py-20 bg-background"><div class="container-custom"><div class="grid md:grid-cols-2 gap-8 max-w-4xl mx-auto"><div class="" style="opacity: 1; transform: none;"><div class="bg-card rounded-2xl p-8 border border-border h-full" style="transform: none;"><div class="flex items-start gap-4"><div class="w-14 h-14 rounded-2xl bg-primary/10 flex items-center justify-center flex-shrink-0"><?php if($w1): ?><img src="<?php echo esc_url($w1); ?>" alt="" class="w-7 h-7 object-contain"><?php else: ?><?php if(!empty($s['work_icon'])) Icons_Manager::render_icon($s['work_icon'],['class'=>'w-7 h-7 text-primary']); ?><?php endif; ?></div><div><h3 class="text-xl font-bold text-foreground mb-3"><?php echo esc_html($s['work_title']??''); ?></h3><div class="space-y-2"><div class="flex items-center gap-2"><?php if($wr1): ?><img src="<?php echo esc_url($wr1); ?>" alt="" class="w-4 h-4 object-contain"><?php else: ?><?php if(!empty($s['work_row1_icon'])) Icons_Manager::render_icon($s['work_row1_icon'],['class'=>'w-4 h-4 text-green-500']); ?><?php endif; ?><p class="text-muted-foreground"><?php echo esc_html($s['work_row1_text']??''); ?></p></div><div class="flex items-center gap-2"><?php if($wr2): ?><img src="<?php echo esc_url($wr2); ?>" alt="" class="w-4 h-4 object-contain"><?php else: ?><?php if(!empty($s['work_row2_icon'])) Icons_Manager::render_icon($s['work_row2_icon'],['class'=>'w-4 h-4 text-red-500']); ?><?php endif; ?><p class="text-muted-foreground"><?php echo esc_html($s['work_row2_text']??''); ?></p></div></div></div></div></div></div><div class="" style="opacity: 1; transform: none;"><div class="bg-card rounded-2xl p-8 border border-border h-full"><div class="flex items-start gap-4"><div class="w-14 h-14 rounded-2xl bg-primary/10 flex items-center justify-center flex-shrink-0"><?php if($li): ?><img src="<?php echo esc_url($li); ?>" alt="" class="w-7 h-7 object-contain"><?php else: ?><?php if(!empty($s['loc_icon'])) Icons_Manager::render_icon($s['loc_icon'],['class'=>'w-7 h-7 text-primary']); ?><?php endif; ?></div><div><h3 class="text-xl font-bold text-foreground mb-3"><?php echo esc_html($s['loc_title']??''); ?></h3><div class="space-y-2"><p class="text-muted-foreground"><?php echo esc_html($s['loc_line1']??''); ?></p><p class="text-muted-foreground"><?php echo esc_html($s['loc_line2']??''); ?></p></div></div></div></div></div></div><div class="" style="opacity: 1; transform: none;"><div class="max-w-xl mx-auto mt-12"><a href="<?php echo esc_url($s['cta_url']['url']??'#'); ?>" target="_blank" rel="noopener noreferrer" class="flex items-center justify-center gap-3 w-full py-5 bg-gradient-to-r from-green-500 to-green-600 hover:from-green-600 hover:to-green-700 text-white rounded-2xl font-medium transition-all text-lg shadow-lg hover:shadow-xl" tabindex="0" style="transform: none;"><?php if($ci): ?><img src="<?php echo esc_url($ci); ?>" alt="" class="w-6 h-6 object-contain"><?php else: ?><?php if(!empty($s['cta_icon'])) Icons_Manager::render_icon($s['cta_icon'],['class'=>'w-6 h-6']); ?><?php endif; ?><?php echo esc_html($s['cta_text']??''); ?></a></div></div></div></section>
    <?php }
}

